                    let contentType = converter.extractContentTypeIfPresent(in: response.headerFields)
                    let body: Operations.retrieve_subscriber.Output.NotFound.Body
                    let chosenContentType = try converter.bestContentType(
                        received: contentType,
                        options: [
                            "application/json"
                        ]
                    )
                    switch chosenContentType {
                    case "application/json":
                        body = try await converter.getResponseBodyAsJSON(
                            Components.Schemas.ErrorMessage.self,
                            from: responseBody,
                            transforming: { value in
                                .json(value)
                            }
                        )
                    default:
                        preconditionFailure("bestContentType chose an invalid content type.")
                    }
                    return .notFound(.init(body: body))
                case 409:
                    return .conflict(.init())
                case 429:
                    let headers: Operations.retrieve_subscriber.Output.TooManyRequests.Headers = .init(
                        Retry_hyphen_After: try converter.getOptionalHeaderFieldAsURI(
                            in: response.headerFields,
                            name: "Retry-After",
                            as: Swift.Int.self
                        ),
                        X_hyphen_RateLimit_hyphen_Limit: try converter.getOptionalHeaderFieldAsURI(
                            in: response.headerFields,
                            name: "X-RateLimit-Limit",
                            as: Swift.Int.self
                        ),
                        X_hyphen_RateLimit_hyphen_Remaining: try converter.getOptionalHeaderFieldAsURI(
                            in: response.headerFields,
                            name: "X-RateLimit-Remaining",
                            as: Swift.Int.self
                        ),
                        X_hyphen_RateLimit_hyphen_Reset: try converter.getOptionalHeaderFieldAsURI(
                            in: response.headerFields,
                            name: "X-RateLimit-Reset",
                            as: Swift.Int.self
                        )
                    )
                    let contentType = converter.extractContentTypeIfPresent(in: response.headerFields)
                    let body: Operations.retrieve_subscriber.Output.TooManyRequests.Body
                    let chosenContentType = try converter.bestContentType(
                        received: contentType,
                        options: [
                            "application/json"
                        ]
                    )
                    switch chosenContentType {
                    case "application/json":
                        body = try await converter.getResponseBodyAsJSON(
                            Components.Schemas.ErrorMessage.self,
                            from: responseBody,
                            transforming: { value in
                                .json(value)
                            }
                        )
                    default:
                        preconditionFailure("bestContentType chose an invalid content type.")
                    }
                    return .tooManyRequests(.init(
                        headers: headers,
                        body: body
                    ))
                default:
                    return .undocumented(
                        statusCode: response.status.code,
                        .init(
                            headerFields: response.headerFields,
                            body: responseBody
                        )
                    )
                }
            }
        )
    }
}
